DROP TABLE IF EXISTS "AuditLog" CASCADE;
DROP TABLE IF EXISTS "Payment" CASCADE;
DROP TABLE IF EXISTS "InvoiceItem" CASCADE;
DROP TABLE IF EXISTS "Invoice" CASCADE;
DROP TABLE IF EXISTS "Provider" CASCADE;
DROP TABLE IF EXISTS "Client" CASCADE;
DROP TABLE IF EXISTS "JournalEntryLine" CASCADE;
DROP TABLE IF EXISTS "JournalEntry" CASCADE;
DROP TABLE IF EXISTS "Account" CASCADE;
DROP TABLE IF EXISTS "BankAccount" CASCADE;
DROP TABLE IF EXISTS "RolePermission" CASCADE;
DROP TABLE IF EXISTS "Permission" CASCADE;
DROP TABLE IF EXISTS "User" CASCADE;
DROP TABLE IF EXISTS "Role" CASCADE;
DROP TABLE IF EXISTS "Company" CASCADE;

CREATE TABLE "Company" ("id" TEXT NOT NULL PRIMARY KEY, "name" VARCHAR(200) NOT NULL, "cuit" VARCHAR(20), "email" VARCHAR(255), "phone" VARCHAR(50), "address" VARCHAR(500), "logo" VARCHAR(500), "plan" VARCHAR(50) NOT NULL DEFAULT 'basico', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);

CREATE TABLE "Role" ("id" TEXT NOT NULL PRIMARY KEY, "name" VARCHAR(50) NOT NULL, "description" VARCHAR(200), "isDefault" BOOLEAN NOT NULL DEFAULT false, "level" INTEGER NOT NULL DEFAULT 0, "companyId" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "Role_companyId_name_key" UNIQUE ("companyId", "name"), CONSTRAINT "Role_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE CASCADE ON UPDATE CASCADE);

CREATE TABLE "Permission" ("id" TEXT NOT NULL PRIMARY KEY, "module" VARCHAR(50) NOT NULL, "action" VARCHAR(50) NOT NULL, "description" VARCHAR(200) NOT NULL, CONSTRAINT "Permission_module_action_key" UNIQUE ("module", "action"));

CREATE TABLE "User" ("id" TEXT NOT NULL PRIMARY KEY, "email" VARCHAR(255) NOT NULL, "password" VARCHAR(500) NOT NULL, "name" VARCHAR(200) NOT NULL, "role" VARCHAR(50) NOT NULL DEFAULT 'admin', "roleId" TEXT, "companyId" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "User_email_key" UNIQUE ("email"), CONSTRAINT "User_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "User_roleId_fkey" FOREIGN KEY ("roleId") REFERENCES "Role"("id") ON DELETE SET NULL ON UPDATE CASCADE);

CREATE TABLE "RolePermission" ("id" TEXT NOT NULL PRIMARY KEY, "roleId" TEXT NOT NULL, "permissionId" TEXT NOT NULL, CONSTRAINT "RolePermission_roleId_permissionId_key" UNIQUE ("roleId", "permissionId"), CONSTRAINT "RolePermission_roleId_fkey" FOREIGN KEY ("roleId") REFERENCES "Role"("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "RolePermission_permissionId_fkey" FOREIGN KEY ("permissionId") REFERENCES "Permission"("id") ON DELETE CASCADE ON UPDATE CASCADE);

CREATE TABLE "Account" ("id" TEXT NOT NULL PRIMARY KEY, "code" VARCHAR(20) NOT NULL, "name" VARCHAR(200) NOT NULL, "type" VARCHAR(50) NOT NULL, "subtype" VARCHAR(50), "parentId" TEXT, "level" INTEGER NOT NULL DEFAULT 1, "balance" DOUBLE PRECISION NOT NULL DEFAULT 0, "companyId" TEXT NOT NULL, CONSTRAINT "Account_companyId_code_key" UNIQUE ("companyId", "code"), CONSTRAINT "Account_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "Account_parentId_fkey" FOREIGN KEY ("parentId") REFERENCES "Account"("id") ON DELETE SET NULL ON UPDATE CASCADE);

CREATE TABLE "JournalEntry" ("id" TEXT NOT NULL PRIMARY KEY, "number" INTEGER NOT NULL, "date" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "description" VARCHAR(500) NOT NULL, "concept" VARCHAR(500), "status" VARCHAR(50) NOT NULL DEFAULT 'borrador', "companyId" TEXT NOT NULL, "totalDebit" DOUBLE PRECISION NOT NULL DEFAULT 0, "totalCredit" DOUBLE PRECISION NOT NULL DEFAULT 0, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "JournalEntry_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE CASCADE ON UPDATE CASCADE);

CREATE TABLE "JournalEntryLine" ("id" TEXT NOT NULL PRIMARY KEY, "journalEntryId" TEXT NOT NULL, "accountId" TEXT NOT NULL, "debit" DOUBLE PRECISION NOT NULL DEFAULT 0, "credit" DOUBLE PRECISION NOT NULL DEFAULT 0, "description" TEXT, CONSTRAINT "JournalEntryLine_journalEntryId_fkey" FOREIGN KEY ("journalEntryId") REFERENCES "JournalEntry"("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "JournalEntryLine_accountId_fkey" FOREIGN KEY ("accountId") REFERENCES "Account"("id") ON DELETE CASCADE ON UPDATE CASCADE);

CREATE TABLE "Client" ("id" TEXT NOT NULL PRIMARY KEY, "code" VARCHAR(20), "name" VARCHAR(200) NOT NULL, "cuit" VARCHAR(20), "email" VARCHAR(255), "phone" VARCHAR(50), "address" VARCHAR(500), "city" VARCHAR(100), "province" VARCHAR(100), "notes" TEXT, "balance" DOUBLE PRECISION NOT NULL DEFAULT 0, "companyId" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "Client_cuit_key" UNIQUE ("cuit"), CONSTRAINT "Client_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE CASCADE ON UPDATE CASCADE);

CREATE TABLE "Provider" ("id" TEXT NOT NULL PRIMARY KEY, "code" VARCHAR(20), "name" VARCHAR(200) NOT NULL, "cuit" VARCHAR(20), "email" VARCHAR(255), "phone" VARCHAR(50), "address" VARCHAR(500), "city" VARCHAR(100), "province" VARCHAR(100), "notes" TEXT, "balance" DOUBLE PRECISION NOT NULL DEFAULT 0, "companyId" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "Provider_cuit_key" UNIQUE ("cuit"), CONSTRAINT "Provider_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE CASCADE ON UPDATE CASCADE);

CREATE TABLE "BankAccount" ("id" TEXT NOT NULL PRIMARY KEY, "name" VARCHAR(200) NOT NULL, "bank" VARCHAR(100), "number" VARCHAR(50), "type" VARCHAR(50) NOT NULL DEFAULT 'cta_corriente', "balance" DOUBLE PRECISION NOT NULL DEFAULT 0, "currency" VARCHAR(10) NOT NULL DEFAULT 'ARS', "companyId" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "BankAccount_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE CASCADE ON UPDATE CASCADE);

CREATE TABLE "Invoice" ("id" TEXT NOT NULL PRIMARY KEY, "number" VARCHAR(50) NOT NULL, "type" VARCHAR(10) NOT NULL, "date" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "dueDate" TIMESTAMP(3), "total" DOUBLE PRECISION NOT NULL DEFAULT 0, "tax" DOUBLE PRECISION NOT NULL DEFAULT 0, "netTotal" DOUBLE PRECISION NOT NULL DEFAULT 0, "amountPaid" DOUBLE PRECISION NOT NULL DEFAULT 0, "status" VARCHAR(50) NOT NULL DEFAULT 'pendiente', "notes" TEXT, "clientId" TEXT, "companyId" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "Invoice_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "Invoice_clientId_fkey" FOREIGN KEY ("clientId") REFERENCES "Client"("id") ON DELETE SET NULL ON UPDATE CASCADE);

CREATE TABLE "InvoiceItem" ("id" TEXT NOT NULL PRIMARY KEY, "description" VARCHAR(500) NOT NULL, "quantity" DOUBLE PRECISION NOT NULL DEFAULT 1, "unitPrice" DOUBLE PRECISION NOT NULL DEFAULT 0, "subtotal" DOUBLE PRECISION NOT NULL DEFAULT 0, "taxRate" DOUBLE PRECISION NOT NULL DEFAULT 21, "taxAmount" DOUBLE PRECISION NOT NULL DEFAULT 0, "invoiceId" TEXT NOT NULL, CONSTRAINT "InvoiceItem_invoiceId_fkey" FOREIGN KEY ("invoiceId") REFERENCES "Invoice"("id") ON DELETE CASCADE ON UPDATE CASCADE);

CREATE TABLE "Payment" ("id" TEXT NOT NULL PRIMARY KEY, "number" VARCHAR(50) NOT NULL, "date" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "amount" DOUBLE PRECISION NOT NULL, "method" VARCHAR(50) NOT NULL DEFAULT 'transferencia', "reference" VARCHAR(100), "type" VARCHAR(20) NOT NULL DEFAULT 'cobro', "notes" TEXT, "invoiceId" TEXT, "clientId" TEXT, "providerId" TEXT, "bankAccountId" TEXT, "companyId" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "Payment_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "Payment_invoiceId_fkey" FOREIGN KEY ("invoiceId") REFERENCES "Invoice"("id") ON DELETE SET NULL ON UPDATE CASCADE, CONSTRAINT "Payment_clientId_fkey" FOREIGN KEY ("clientId") REFERENCES "Client"("id") ON DELETE SET NULL ON UPDATE CASCADE, CONSTRAINT "Payment_providerId_fkey" FOREIGN KEY ("providerId") REFERENCES "Provider"("id") ON DELETE SET NULL ON UPDATE CASCADE, CONSTRAINT "Payment_bankAccountId_fkey" FOREIGN KEY ("bankAccountId") REFERENCES "BankAccount"("id") ON DELETE SET NULL ON UPDATE CASCADE);

CREATE TABLE "AuditLog" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "userName" VARCHAR(200) NOT NULL, "action" VARCHAR(50) NOT NULL, "entity" VARCHAR(50) NOT NULL, "entityId" TEXT, "details" TEXT, "companyId" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "AuditLog_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "AuditLog_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE);

CREATE INDEX "AuditLog_companyId_idx" ON "AuditLog"("companyId");
CREATE INDEX "AuditLog_entity_idx" ON "AuditLog"("entity");
CREATE INDEX "AuditLog_createdAt_idx" ON "AuditLog"("createdAt");

